VALUES
  ('judicial-57f41407-moex-00103', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲以一訴請求乙返還租賃物及清償借款，下列敘述何者錯誤？', '["甲請求之二法律關係及其攻擊或防禦方法如無牽連關係，法院得命分別辯論", "甲請求之二法律關係，於法院命分別辯論時，亦應合併裁判，不得分別裁判", "就請求返還租賃物部分，如有停止訴訟之事由，法院得命分別辯論及分別裁判", "丙於該訴訟繫屬中，主張其為該租賃物所有權人，以甲、乙為被告，起訴請求乙返還該租賃物，法 院原則上應合併辯論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00104', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於裁判，下列敘述何者正確？', '["判決均應公告", "判決均應宣示", "裁定均不用宣示", "裁定均應送達"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00105', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於民事第一審通常訴訟程序訴之變更或追加，下列敘述何者錯誤？', '["當事人、訴訟標的及其原因事實、應受判決事項之聲明，如其一發生變動或追加，即生是否有訴之 變更或追加之問題", "為擴大訴訟解決紛爭，現行民事訴訟法規定於訴狀送達後，原則上原告得任意為訴之變更或追加", "原告於起訴後變更或追加之新訴，如專屬其他法院管轄，縱經他造同意，亦不得為之", "訴之變更如合法，原訴視為撤回，法院應專就變更後之新訴裁判"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00106', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於民事第一審通常訴訟程序中訴之撤回，下列敘述何者錯誤？', '["原告之訴訟代理人必須有受民事訴訟法第70條第1項但書所定之特別委任，始得代理原告撤回其訴", "被告於準備程序期日已為本案之陳述及答辯後，原告撤回其訴，亦應得被告同意", "訴之撤回使訴訟繫屬歸於消滅，因此必須以書狀為之，不得於期日時以言詞向法院為撤回", "訴之撤回合法生效後，本案訴訟程序當然終結，法院無須為任何形式裁判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00107', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟上和解，下列敘述何者正確？', '["當事人不得將訴訟標的外之法律關係納為訴訟上和解之對象", "訴訟上和解僅限原告與被告間始得成立，第三人無從參加而成立訴訟上和解", "訴訟當事人間之意思表示一旦合致，即有效成立訴訟上和解，不以作成和解筆錄為必要", "第三人如因訴訟上和解而受不利時，得準用民事訴訟法關於第三人撤銷訴訟程序之規定，請求救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00108', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於調解程序，下列敘述何者錯誤？', '["第一審訴訟繫屬中，得經兩造合意，將事件移付調解；且為求調解程序之效率，法院得於調解程序 中併行言詞辯論期日", "調解成立者，與訴訟上和解有同一之效力", "強制調解之事件，法院未行調解程序而直接進行言詞辯論時，不得認為訴訟程序有重大瑕疵", "當事人無正當理由不於調解期日到場者，法院得以裁定處新臺幣3,000元以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00109', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於簡易訴訟程序與小額訴訟程序，下列敘述何者正確？', '["適用兩者之事件，法院所為被告敗訴之判決，均應依職權宣告假執行", "適用兩者之事件，在起訴前，均應先經調解程序", "兩者之第二審程序，均得為訴之變更、追加或提起反訴", "對於兩者第二審法院所為之判決，均得提起第三審上訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00110', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於簡易訴訟程序，下列敘述何者錯誤？', '["言詞辯論期日，當事人一造經合法通知無正當理由不到場，得由到場之他造辯論而為判決", "第二審確定判決，如有足影響於判決之重要證據漏未審酌，得提起再審之訴", "關於財產權之訴訟，其訴訟標的之金額或價額逾新臺幣10萬元，在新臺幣50萬元以下者，適用簡 易程序", "第二審判決適用法規顯有錯誤，即得上訴最高法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00111', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲起訴請求乙給付新臺幣（下同）150萬元，法院判命乙給付40萬元，甲具狀提起一部上訴，請求命 乙再給付70萬元。下列敘述何者正確？', '["甲於到場聆聽第一審法院判決宣示後，毋庸待收受該判決，即可提起上訴", "甲所受敗訴判決，未上訴部分，已先行確定", "如甲欲撤回上訴，應得乙之同意", "上訴期間，自判決對外表示時即起算不變期間20日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00112', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於民事第二審通常訴訟程序中附帶上訴，下列敘述何者錯誤？', '["第二審判決經第三審法院發回或發交後，被上訴人就原第一審判決未聲明不服之部分，不得為附帶 上訴", "普通共同訴訟人中之一人或數人提起上訴者，其效力不及於他共同訴訟人，故對於未提起上訴之人， 不得提起附帶上訴", "第二審上訴因不合程式而被駁回者，即因此喪失其上訴權，自不得於他造之上訴提起附帶上訴", "第二審附帶上訴，為當事人對於所受不利益之第一審終局判決聲明不服之方法，在第一審受勝訴判 決之當事人，自無許其提起附帶上訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
